def sign():
    ts = str(round(time.time() * 1000))
    s  = f"{ts}\n{SECRET}"
    sig = urllib.parse.quote_plus(
        base64.b64encode(
            hmac.new(SECRET.encode(), s.encode(), digestmod=hashlib.sha256).digest()
        )
    )
    return ts, sig

def send_markdown(title, text):
    ts, sig = sign()
    url = f"{WEBHOOK}&timestamp={ts}&sign={sig}"
    msg = {"msgtype": "markdown", "markdown": {"title": title, "text": text}}
    r = requests.post(url, json=msg, timeout=15)
    print(r.json())

